module.exports = {
  config: {
cooldowns: 10,
credits: 'CHAND',
premium: false,
permission: 0,
version: '1.0.0',
    name: 'tid',
    aliases: ['threadid', 'gid'],
    description: 'Get the thread/group ID',
    usage: 'tid',
    category: 'Utility',
    prefix: true
  },
  
  async run({ api, event, send }) {
    const { threadID, isGroup } = event;
    
    return send.reply(`━❮📋❯━━━❪✨❫━━━❮📋❯━\n🔒 ${isGroup ? '🅖𝐫𝐨𝐮𝐩' : '🅣𝐡𝐫𝐞𝐚𝐝'} 🅘𝐃:\n─────────────────\n${threadID}\n━❮📋❯━━━❪✨❫━━━❮📋❯━`);
  }
};
